import{_ as e,c as i,o as a,ae as l}from"./chunks/framework.z0sZ1NT9.js";const u=JSON.parse('{"title":"Vite","description":"","frontmatter":{},"headers":[],"relativePath":"articles/practice/八股/vite.md","filePath":"articles/practice/八股/vite.md"}'),s={name:"articles/practice/八股/vite.md"};function o(r,t,d,n,h,p){return a(),i("div",null,t[0]||(t[0]=[l('<h1 id="vite" tabindex="-1">Vite <a class="header-anchor" href="#vite" aria-label="Permalink to &quot;Vite&quot;">​</a></h1><h2 id="vite-的目的" tabindex="-1">Vite 的目的 <a class="header-anchor" href="#vite-的目的" aria-label="Permalink to &quot;Vite 的目的&quot;">​</a></h2><p>Vite 是一种面向现代前端开发的构建工具，它的核心目标不是“先把整个项目打包好再启动开发服务”，而是尽可能利用浏览器原生的 ES Module 能力，在开发阶段按需提供源码，从而显著缩短冷启动时间和热更新反馈时间。和 webpack 这类传统打包器相比，Vite 更强调开发体验，生产环境则通过 Rollup 完成高质量打包。</p><p>它解决的核心问题可以概括为两类：</p><ol><li>开发阶段启动慢、改动反馈慢。</li><li>项目变大后，频繁完整打包带来的等待成本高。</li></ol><h2 id="vite-的开发流程" tabindex="-1">Vite 的开发流程 <a class="header-anchor" href="#vite-的开发流程" aria-label="Permalink to &quot;Vite 的开发流程&quot;">​</a></h2><p>Vite 在开发环境下采用“按需编译、即时响应”的方式工作。启动时，它会先启动一个本地开发服务器，但不会像 webpack 那样先把整个应用打成一个巨大的 bundle，而是把源码文件按需返回给浏览器。</p><h3 id="_1-启动开发服务器" tabindex="-1">1. 启动开发服务器 <a class="header-anchor" href="#_1-启动开发服务器" aria-label="Permalink to &quot;1. 启动开发服务器&quot;">​</a></h3><p>Vite 启动后会先读取 <code>vite.config.js</code>，合并命令行参数和配置项，然后创建开发服务器。此时不会进行完整打包，而是准备好文件读取、插件管线和依赖预构建流程。</p><h3 id="_2-入口-html-与模块脚本" tabindex="-1">2. 入口 HTML 与模块脚本 <a class="header-anchor" href="#_2-入口-html-与模块脚本" aria-label="Permalink to &quot;2. 入口 HTML 与模块脚本&quot;">​</a></h3><p>使用 Vite 创建项目时，入口通常会写在 <code>index.html</code> 里，并通过下面这种方式引用脚本：</p><div class="language-html vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">html</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">&lt;</span><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">script</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> type</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;module&quot;</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> src</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;/src/main.js&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">&gt;&lt;/</span><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">script</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">&gt;</span></span></code></pre></div><p>这里的 <code>type=&quot;module&quot;</code> 是Vite构建项目时写入的。Vite 会把 <code>index.html</code> 当作应用入口来处理，并在开发和构建过程中识别这种模块脚本写法。</p><p><code>type=&quot;module&quot;</code> 的作用是告诉浏览器：这个脚本要按照 ES Module 的规则去加载和执行。这样浏览器才能继续解析 <code>import</code> / <code>export</code>，并按依赖关系递归请求后续模块。</p><h3 id="_3-浏览器按需请求源码" tabindex="-1">3. 浏览器按需请求源码 <a class="header-anchor" href="#_3-浏览器按需请求源码" aria-label="Permalink to &quot;3. 浏览器按需请求源码&quot;">​</a></h3><p>开发模式下，浏览器通过原生 <code>import</code> 加载模块。Vite 会拦截这些请求，对源文件做必要的转换，比如：</p><ul><li>将 TypeScript、JSX、Vue、React 等代码转换为浏览器可执行的 JavaScript。</li><li>处理 CSS、图片、字体等静态资源。</li><li>注入开发所需的辅助逻辑。</li></ul><h3 id="_4-依赖预构建" tabindex="-1">4. 依赖预构建 <a class="header-anchor" href="#_4-依赖预构建" aria-label="Permalink to &quot;4. 依赖预构建&quot;">​</a></h3><p>对 <code>node_modules</code> 里的第三方依赖，Vite 会先使用 esbuild 做预构建和转换，减少大量小文件请求，并把 CommonJS / UMD 依赖尽量转成浏览器更容易处理的形式。</p><p>这个步骤的目的主要有两个：</p><ol><li>提升浏览器首次打开页面时的模块加载效率。</li><li>降低浏览器在开发阶段处理大量依赖文件时的开销。</li></ol><p>这一步的实现大致如下：</p><ol><li>Vite 启动开发服务器后，会先扫描项目中的入口文件和静态导入，找出需要预处理的裸模块依赖（非相对路径）。</li><li>对这些依赖，Vite 调用 esbuild 进行快速打包和格式转换，<strong>把多个分散的小模块合并成少量可直接被浏览器加载的预构建产物</strong>。</li><li>预构建结果会写入本地缓存目录，常见位置是 <code>node_modules/.vite</code>，下次启动时可以直接复用，避免重复构建。</li><li>如果依赖内容、配置或锁文件发生变化，Vite 会根据 hash 重新触发预构建，保证缓存和实际依赖一致。</li></ol><p>所以这里并不是把整个应用打包一遍，而是只把第三方依赖先“整理好”，让浏览器在开发阶段能够更快、更稳定地加载这些模块。</p><h3 id="_5-插件与转换" tabindex="-1">5. 插件与转换 <a class="header-anchor" href="#_5-插件与转换" aria-label="Permalink to &quot;5. 插件与转换&quot;">​</a></h3><p>Vite 的插件体系基于 Rollup 的插件接口扩展而来，开发阶段同样可以在请求模块时介入转换过程。常见用途包括：</p><ul><li>处理框架语法，例如 Vue SFC、React JSX。</li><li>注入环境变量。</li><li>修改 HTML、静态资源和构建产物。</li></ul><h3 id="_6-生产环境构建" tabindex="-1">6. 生产环境构建 <a class="header-anchor" href="#_6-生产环境构建" aria-label="Permalink to &quot;6. 生产环境构建&quot;">​</a></h3><p>当执行构建命令时，Vite 会切换到生产模式，使用 Rollup 对模块进行打包、代码分割和资源优化，最终输出可部署的静态资源。</p><h2 id="vite-中的-esbuild-和-rollup" tabindex="-1">Vite 中的 esbuild 和 Rollup <a class="header-anchor" href="#vite-中的-esbuild-和-rollup" aria-label="Permalink to &quot;Vite 中的 esbuild 和 Rollup&quot;">​</a></h2><p>Vite 之所以启动快、构建体验好，核心就在于它把不同阶段的工作交给了最适合的工具：开发阶段更多依赖 esbuild，生产构建主要依赖 Rollup。</p><h3 id="esbuild" tabindex="-1">esbuild <a class="header-anchor" href="#esbuild" aria-label="Permalink to &quot;esbuild&quot;">​</a></h3><p>esbuild 是一个基于 Go 实现的超快打包与转换工具，Vite 主要把它用在开发阶段和部分预处理场景中。它的特点是速度很快，适合做高频、轻量的转换工作。</p><p>在 Vite 里，esbuild 主要负责：</p><ul><li>依赖预构建，把 <code>node_modules</code> 中的依赖提前处理成更适合浏览器加载的形式。</li><li>转换部分源码语法，比如 TypeScript、JSX 等。</li><li>在开发阶段承担一些快速转译工作，减少冷启动时间。</li></ul><p>esbuild 的优势是快，但它并不是 Vite 生产构建的主力打包器，所以在复杂的插件生态、细粒度打包控制方面不如 Rollup 灵活。</p><h3 id="rollup" tabindex="-1">Rollup <a class="header-anchor" href="#rollup" aria-label="Permalink to &quot;Rollup&quot;">​</a></h3><p>Rollup 是一个更偏向“打包成品”的工具，Vite 在生产环境构建时会调用它来完成真正的模块打包。它擅长把 ES Module 进行静态分析，进而完成代码分割、Tree Shaking 和最终资源输出。</p><p>在 Vite 里，Rollup 主要负责：</p><ul><li>生产环境打包。</li><li>代码分割和 chunk 生成。</li><li>Tree Shaking 和静态分析。</li><li>通过插件体系处理构建阶段的资源输出。</li></ul><p>可以简单理解为：esbuild 负责“快”，Rollup 负责“完整且灵活”。Vite 把开发和构建拆开处理，正是为了同时兼顾开发速度和最终产物质量。</p><h3 id="rollup-和-webpack打包进行对比" tabindex="-1">Rollup 和 webpack打包进行对比 <a class="header-anchor" href="#rollup-和-webpack打包进行对比" aria-label="Permalink to &quot;Rollup 和 webpack打包进行对比&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:left;">特性</th><th style="text-align:left;">Rollup</th><th style="text-align:left;">webpack</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>定位与核心目标</strong></td><td style="text-align:left;">专注于 ES Module 的打包器，致力于生成小巧干净的代码。</td><td style="text-align:left;">处理所有的前端资源的极客级别、功能强大的模块打包器。</td></tr><tr><td style="text-align:left;"><strong>适用场景</strong></td><td style="text-align:left;"><strong>类库 / 工具库开发</strong>（例如 Vue、React 等底层源码和组件库打包）。</td><td style="text-align:left;"><strong>复杂的单页应用 / 多页业务应用 (SPA/MPA) 开发</strong>。</td></tr><tr><td style="text-align:left;"><strong>代码输出质量</strong></td><td style="text-align:left;">输出代码非常纯粹、极致扁平化（作用域提升 Hoisting），不注入多余的运行时代码。</td><td style="text-align:left;">会注入较多自定义的打包与模块依赖加载代码 (runtime / manifest)，产物略显臃肿。</td></tr><tr><td style="text-align:left;"><strong>Tree Shaking</strong></td><td style="text-align:left;">原生具备优秀的基于 ESM 的静态分析，Tree Shaking 效果好且彻底。</td><td style="text-align:left;">同样支持 Tree Shaking，但在处理复杂或混用的 CommonJS/ESM 模块时可能略逊一筹。</td></tr><tr><td style="text-align:left;"><strong>资源加载与处理</strong></td><td style="text-align:left;">侧重于 JS/TS 的打包，处理 CSS、图片等非代码资源需依赖各式插件，不够开箱即用。</td><td style="text-align:left;">一切皆模块，借助其强大的 Loader 机制，CSS、图片、字体文件等万物皆可直接 <code>import</code> 处理。</td></tr><tr><td style="text-align:left;"><strong>代码分割与动态加载</strong></td><td style="text-align:left;">支持代码分割功能，但体系较为基础，体验不够webpack完善。</td><td style="text-align:left;">提供原生且成熟度极高的动态分包 (Code Splitting) 和按需加载能力。</td></tr><tr><td style="text-align:left;"><strong>开发体验与 HMR</strong></td><td style="text-align:left;">传统意义上作为纯构建工具，原生并没有很强的 DevServer 以及热模块替换(HMR)体系。</td><td style="text-align:left;">拥有极其强大、成熟的本地开发服务器 (webpack-dev-server) 以及完善的热更新(HMR)体系。</td></tr></tbody></table><h2 id="vite-的热重载过程" tabindex="-1">Vite 的热重载过程 <a class="header-anchor" href="#vite-的热重载过程" aria-label="Permalink to &quot;Vite 的热重载过程&quot;">​</a></h2><p>Vite 的热更新依赖浏览器端的原生模块边界和 WebSocket 通信。相比 webpack 的 HMR，Vite 在开发阶段通常更轻量，更新路径也更短。</p><ol><li>当源文件发生变化时，Vite 监听到文件改动。</li><li>服务端根据变更模块重新转换对应文件，并判断它是否能被 HMR 接受。</li><li>Vite 通过 WebSocket 向浏览器发送更新消息，通知哪些模块发生了变化。</li><li>浏览器端根据消息请求新的模块代码，并尝试局部替换。</li><li>如果某个模块无法热替换，Vite 会退化为整页刷新。</li></ol><p>Vite 的 HMR 之所以快，关键在于它通常只处理受影响的模块，而不是对整个应用重新打包。</p><h2 id="如何使用-vite-来优化前端性能" tabindex="-1">如何使用 Vite 来优化前端性能 <a class="header-anchor" href="#如何使用-vite-来优化前端性能" aria-label="Permalink to &quot;如何使用 Vite 来优化前端性能&quot;">​</a></h2><h3 id="依赖预构建" tabindex="-1">依赖预构建 <a class="header-anchor" href="#依赖预构建" aria-label="Permalink to &quot;依赖预构建&quot;">​</a></h3><p>Vite 会在开发阶段使用 esbuild 预构建依赖，这能显著减少重复解析和请求数量。对大型项目来说，这一步往往能明显改善启动速度。</p><h3 id="按需加载" tabindex="-1">按需加载 <a class="header-anchor" href="#按需加载" aria-label="Permalink to &quot;按需加载&quot;">​</a></h3><p>和 webpack 一样，Vite 也支持通过动态导入实现代码分割。</p><div class="language-javascript vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">javascript</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">const</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> SomeComponent</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> =</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> () </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=&gt;</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> import</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&#39;./SomeComponent.vue&#39;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">);</span></span></code></pre></div><p>对于路由级别、功能级别的模块，按需加载可以降低首屏负担，避免一次性加载过多代码。</p><h3 id="静态资源优化" tabindex="-1">静态资源优化 <a class="header-anchor" href="#静态资源优化" aria-label="Permalink to &quot;静态资源优化&quot;">​</a></h3><p>Vite 会对图片、字体、媒体文件等静态资源做统一处理。体积较小的资源可能被内联，大资源则以单独文件形式输出，便于缓存和按需加载。</p><h3 id="构建压缩" tabindex="-1">构建压缩 <a class="header-anchor" href="#构建压缩" aria-label="Permalink to &quot;构建压缩&quot;">​</a></h3><p>在生产构建中，Vite 通过 Rollup 完成打包，并配合压缩插件对 JavaScript、CSS 进行压缩，以减小最终产物体积。</p><h3 id="代码分割" tabindex="-1">代码分割 <a class="header-anchor" href="#代码分割" aria-label="Permalink to &quot;代码分割&quot;">​</a></h3><p>Vite 支持基于动态导入和 Rollup 配置的代码分割。你可以把不常用的页面、组件、业务模块拆成独立 chunk，减少首屏阻塞。</p><h3 id="预加载与预取" tabindex="-1">预加载与预取 <a class="header-anchor" href="#预加载与预取" aria-label="Permalink to &quot;预加载与预取&quot;">​</a></h3><p>Vite 在生产构建中会为动态导入生成相应的模块预加载逻辑，帮助浏览器提前准备后续需要的模块。对于更细粒度的预取策略，通常需要结合路由方案或第三方插件实现。</p><h2 id="vite-和-webpack-的区别" tabindex="-1">Vite 和 webpack 的区别 <a class="header-anchor" href="#vite-和-webpack-的区别" aria-label="Permalink to &quot;Vite 和 webpack 的区别&quot;">​</a></h2><ol><li>webpack 更偏向“先打包再服务”，Vite 更偏向“按需服务、按需编译”。</li><li>webpack 开发阶段依赖较重，Vite 开发阶段借助原生 ESM 和 esbuild 预构建，启动通常更快。</li><li>webpack 的 HMR 体系更传统，Vite 的 HMR 更接近直接更新单个模块。</li><li>webpack 的构建核心更统一，Vite 的开发和生产分别由不同机制承担，开发用原生 ESM 和插件转换，生产用 Rollup 打包。</li></ol>',64)]))}const k=e(s,[["render",o]]);export{u as __pageData,k as default};
